import os
import json
import base64
import logging
from datetime import datetime, timezone

from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1

logging.basicConfig(level=logging.INFO)

storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

PROJECT_ID = os.environ.get("GCP_PROJECT") or os.environ.get("GOOGLE_CLOUD_PROJECT")
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC")
FIRESTORE_COLLECTION = os.environ.get("FIRESTORE_COLLECTION", "processed_files")


def _get_bucket_and_name(event):
    bucket = event.get("bucket")
    name = event.get("name")
    if not bucket or not name:
        raise ValueError("Missing bucket or name in event")
    return bucket, name


def _download_file(bucket_name, blob_name):
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(blob_name)
    return blob.download_as_bytes()


def _write_firestore_record(bucket_name, blob_name, content_bytes, metadata=None):
    doc_id = f"{bucket_name}:{blob_name}"
    doc_ref = firestore_client.collection(FIRESTORE_COLLECTION).document(doc_id)
    record = {
        "bucket": bucket_name,
        "name": blob_name,
        "size": len(content_bytes),
        "updated_at": datetime.now(timezone.utc),
        "metadata": metadata or {},
    }
    doc_ref.set(record, merge=True)
    return doc_id, record


def _publish_message(bucket_name, blob_name, doc_id, size):
    if not PUBSUB_TOPIC:
        return None

    topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)
    message = {
        "bucket": bucket_name,
        "name": blob_name,
        "firestore_doc_id": doc_id,
        "size": size,
        "processed_at": datetime.now(timezone.utc).isoformat(),
    }
    data = json.dumps(message).encode("utf-8")
    future = publisher.publish(topic_path, data=data, content_type="application/json")
    return future.result()


def process_gcs_file(event, context):
    bucket_name, blob_name = _get_bucket_and_name(event)

    logging.info("Processing file gs://%s/%s", bucket_name, blob_name)

    content = _download_file(bucket_name, blob_name)

    metadata = {
        "event_id": getattr(context, "event_id", None),
        "event_type": getattr(context, "event_type", None),
        "timestamp": getattr(context, "timestamp", None),
    }

    doc_id, record = _write_firestore_record(bucket_name, blob_name, content, metadata=metadata)
    message_id = _publish_message(bucket_name, blob_name, doc_id, record["size"])

    logging.info(
        "Processed gs://%s/%s -> firestore doc %s%s",
        bucket_name,
        blob_name,
        doc_id,
        f", pubsub message {message_id}" if message_id else "",
    )

    return {
        "status": "ok",
        "bucket": bucket_name,
        "name": blob_name,
        "firestore_doc_id": doc_id,
        "pubsub_message_id": message_id,
    }